INSERT INTO words (id, page_num, word, full_name, overview_en, overview_jp, usage, examples, quick_memory_en, quick_memory_jp, studied)
VALUES
  (1, 1, '3C分析', '', 'A strategic framework analyzing three customer variables: Customer, Competitor, and Company.', '顧客・競合・自社の3つの要素を分析する戦略フレームワーク (こきゃく・きょうごう・じしゃ)', 'Used in marketing strategy to understand market position and find competitive advantages.', ', New product launch planning , Market entry strategy for startups , Annual marketing strategy review', '3C = Customer, Competitor, Company.', '3C = 顧客・競合・自社', false),
  (2, 1, 'ASP (Application Service Provider)', '', 'A company that provides software applications over the internet.', 'インターネット経由でソフトウェアを提供する事業者 (アプリケーションサービスプロバイダ)', 'Used by businesses to rent software instead of buying and installing it locally.', ', Salesforce CRM as a service , QuickBooks Online for accounting , Google Workspace for email and docs', 'Software rental over internet.', 'ソフトを借りて使う仕組み', false),
  (3, 1, 'BCP (Business Continuity Plan)', '', 'A plan to keep business running during disasters or major disruptions.', '災害時も事業を続けるための計画 (ビジネス・コンティニュイティ・プラン)', 'Used by companies to prepare for earthquakes, cyberattacks, pandemics, or system failures.', ', Data backup at remote site , Alternate office setup , Employee communication protocol during crisis', 'Keep business alive during disaster.', '災害時に事業を止めない計画', false),
  (4, 1, 'BPM (Business Process Management)', '', 'A discipline to improve, manage, and automate business processes.', '業務プロセスを改善・管理・自動化する手法 (ビジネス・プロセス・マネジメント)', 'Used to make workflows more efficient, reduce errors, and cut costs.', ', Invoice approval automation , Customer complaint handling流程 , Employee onboarding process redesign', 'Manage and improve workflows.', '業務の流れを良くする管理', false),
  (5, 1, 'BPO (Business Process Outsourcing)', '', 'Contracting business operations to an external provider.', '業務を外部会社に委託すること (ビジネス・プロセス・アウトソーシング)', 'Used to reduce costs and focus on core business by outsourcing non-core tasks.', ', Payroll processing to ADP , Call center operations to a third party , IT helpdesk outsourcing', 'Hire others to do back-office work.', '業務を外注すること', false),
  (6, 1, 'BPR (Business Process Reengineering)', '', 'Radically redesigning business processes from scratch for major improvements.', '業務プロセスを根本から再設計すること (ビジネス・プロセス・リエンジニアリング)', 'Used when a company needs dramatic cost reduction, quality improvement, or speed increase.', ', Ford''s procurement process redesign , Insurance claim processing overhaul , Bank loan approval simplification', 'Start from zero to transform processes.', 'ゼロから業務を組み直す', false),
  (7, 1, 'BSC (Balanced Scorecard)', '', 'A strategic performance management framework with four perspectives: Financial, Customer, Internal Process, Learning & Growth.', '財務・顧客・内部プロセス・学習成長の4視点で業績を測る手法 (バランスト・スコアカード)', 'Used to translate company strategy into measurable KPIs across all departments.', ', Retail chain tracking customer satisfaction , Manufacturer monitoring production efficiency , Hospital measuring patient care quality', 'Measure strategy from four angles.', '4つの視点で経営を評価', false),
  (8, 1, 'BTO (Build to Order)', '', 'Manufacturing products only after receiving customer orders.', '注文を受けてから生産する方式 (ビルド・トゥ・オーダー)', 'Used to reduce inventory risk and customize products to customer needs.', ', Dell computers built per order , Custom car manufacturing , Tailored suit production', 'Make after order, not before.', '受注してから作る生産方式', false),
  (9, 1, 'BYOD (Bring Your Own Device)', '', 'Company policy allowing employees to use personal devices for work.', '従業員の私物端末を仕事に使うことを許可する方針 (ブリング・ユア・オウン・デバイス)', 'Used in companies to reduce hardware costs and let employees work on familiar devices.', ', Using personal iPhone for work email , Laptop with company VPN access , Bringing tablet to meetings for notes', 'Work from your own phone/PC.', '自分の端末を仕事で使う', false),
  (10, 1, 'CA (Certificate Authority)', '', 'A trusted entity that issues digital certificates for secure communication.', 'デジタル証明書を発行する信頼できる機関 (じゅしょうにんしょうきかん / 証明機関)', 'Used to verify website identity and enable HTTPS for secure browsing.', ', VeriSign issuing SSL certificates , Let''s Encrypt free certificates , Company internal CA for employee IDs', 'Issuer of digital ID cards for websites.', '電子証明書の発行機関', false),
  (11, 1, 'CAD (Computer-Aided Design)', '', 'Software for creating precise 2D or 3D technical drawings.', 'コンピュータを使って設計図を作成するソフト (キャド)', 'Used by engineers, architects, and product designers to create and modify designs digitally.', ', AutoCAD for architectural plans , SolidWorks for mechanical parts , Fusion 360 for 3D printing models', 'Digital drawing tool for designers.', '設計図をパソコンで作る', false),
  (12, 1, 'CAPTCHA', '', 'A test to tell humans and bots apart, often distorted text or image selection.', '人間とbotを区別するテスト (キャプチャ)', 'Used on websites to prevent automated spam, fake account creation, and brute-force attacks.', ', Selecting traffic lights in images , Typing distorted letters for login , Checkbox \I am not a robot\', 'Human-or-bot test.', '人間かbotかを確かめる', false),
  (13, 1, 'CEO (Chief Executive Officer)', '', 'The highest-ranking executive in a company, responsible for major decisions.', '会社の最高経営責任者 (さいこうけいえいせきにんしゃ / シーイーオー)', 'Leads company strategy, represents the company to board and public, and has final authority.', ', Tim Cook of Apple , Satya Nadella of Microsoft , Founder-CEO of a startup', 'Top boss of a company.', '会社のトップ', false),
  (14, 1, 'CIO (Chief Information Officer)', '', 'The executive in charge of IT strategy and computer systems.', 'IT戦略と情報システムを統括する役職 (最高情報責任者 / さいこうじょうほうせきにんしゃ)', 'Used to align technology investments with business goals and manage IT risks.', ', Migrating company to cloud , Leading digital transformation , Overseeing cybersecurity strategy', 'Boss of company IT.', 'IT全体の責任者', false),
  (15, 1, 'CRM (Customer Relationship Management)', '', 'A strategy and software system to manage interactions with customers.', '顧客関係管理 (こきゃくかんけいかんり / シーアールエム)', 'Used by sales, marketing, and support teams to track leads, manage contacts, and analyze customer data.', ', Salesforce tracking sales pipeline , HubSpot managing email campaigns , Zendesk handling support tickets', 'Manage customer interactions systematically.', '顧客情報を一括管理', false),
  (16, 1, 'CSF (Critical Success Factor)', '', 'Key activities or conditions necessary for an organization to achieve its mission.', '組織が成功するために不可欠な要素 (クリティカル・サクセス・ファクター)', 'Used in strategic planning to identify what must go right for the business to succeed.', ', For an airline: on-time departures , For an e-commerce site: website uptime , For a hospital: patient safety', 'Must-have conditions for success.', '成功に必須の条件', false),
  (17, 1, 'CSIRT (Computer Security Incident Response Team)', '', 'A specialized team that handles cybersecurity incidents and breaches.', 'サイバーセキュリティ事故に対応する専門チーム (シーサート)', 'Used to detect, analyze, contain, and recover from cyberattacks or system compromises.', ', Responding to ransomware attack , Investigating data breach , Managing DDoS attack mitigation', 'Cyber emergency response team.', 'セキュリティ事故対応チーム', false),
  (18, 1, 'CSR (Corporate Social Responsibility)', '', 'A self-regulating business model that holds companies accountable to society and environment.', '企業の社会的責任 (きぎょうのしゃかいてきせきにん)', 'Used by companies to improve public image, meet regulations, and attract responsible investors.', ', Reducing carbon emissions , Fair labor practices in supply chain , Donating percentage of profits to charity', 'Business doing good for society.', '会社の社会に対する責任', false),
  (19, 1, 'DFD (Data Flow Diagram)', '', 'A diagram showing how data moves through a system, including sources, processes, and destinations.', 'データの流れを図示したもの (データ・フロー・ダイアグラム)', 'Used by system analysts to document existing systems or design new ones.', ', Order processing system diagram , Student registration flow chart , ATM withdrawal data movement', 'Map of data movement in a system.', 'データの流れ図', false),
  (20, 1, 'DRAM (Dynamic Random Access Memory)', '', 'A type of computer memory that stores each bit in a capacitor, requiring constant refresh.', 'コンピュータの主記憶装置の一種 (ディーラム / ダイナミックRAM)', 'Used as the main memory (RAM) in computers, smartphones, and game consoles.', ', DDR4 RAM in laptops , GDDR6 in graphics cards , LPDDR in smartphones', 'Main memory that needs refreshing.', 'パソコンの主記憶', false),
  (21, 1, 'EA (Enterprise Architecture)', '', 'A framework that aligns business strategy with IT infrastructure and processes.', 'ビジネス戦略とITを整合させる設計手法 (エンタープライズ・アーキテクチャ)', 'Used by large organizations to manage complexity and guide technology investments.', ', TOGAF framework implementation , Government digital transformation planning , Banking system integration after merger', 'Blueprint for business + IT alignment.', '会社全体の設計図', false),
  (22, 1, 'ERP (Enterprise Resource Planning)', '', 'Integrated software for managing core business processes like finance, HR, and supply chain.', '基幹業務システム (きかんぎょうむシステム / イーアールピー)', 'Used to unify data across departments into a single database, eliminating silos.', ', SAP for multinational corporations , Oracle NetSuite for mid-size firms , Microsoft Dynamics 365', 'All-in-one business software.', '会社全体の統合システム', false),
  (23, 1, 'E-R図 (Entity Relationship Diagram)', '', 'A diagram showing entities (data tables) and relationships between them.', 'テーブル間の関係を図示したデータベース設計図 (イーアールず)', 'Used by database designers to model data structure before building a database.', ', Customer-Order-Product relationship model , Library book-lending system design , Hospital patient-record schema', 'Database relationship picture.', 'データベースの関係図', false),
  (24, 1, 'FP法 (Function Point Method)', '', 'A method to measure software size based on user-requested functions, not lines of code.', 'ユーザー機能からソフトウェア規模を測定する手法 (ファンクションポイントほう)', 'Used to estimate project cost, effort, and duration in early development stages.', ', Calculating development cost for banking app , Comparing productivity across teams , Outsourcing contract pricing', 'Measure software by its features.', '機能ベースのソフト規模測定', false),
  (25, 1, 'HTML (HyperText Markup Language)', '', 'The standard language for creating web pages using tags to structure content.', 'ウェブページを作るための標準言語 (エイチティーエムエル)', 'Used by web developers to structure text, images, links, and forms on websites.', ', Creating a blog post with headings and paragraphs , Building a product catalog with images , Designing a contact form', 'Language for building web pages.', 'ホームページを作る言語', false),
  (26, 1, 'ICT (Information and Communication Technology)', '', 'An umbrella term for all technologies used to handle information and communication.', '情報通信技術 (じょうほうつうしんぎじゅつ)', 'Used in education, business, and government to enable digital communication and data processing.', ', School tablets and online learning platforms , Video conferencing for remote work , Government digital ID systems', 'All tech for info + communication.', '情報と通信の技術全般', false),
  (27, 1, 'IDS (Intrusion Detection System)', '', 'A security tool that monitors network traffic and alerts on suspicious activity.', '不正侵入を監視して警告するシステム (いんたんじょんおう)', 'Used to detect cyberattacks but does not block them automatically (unlike IPS).', ', Snort open-source IDS , Alerting on multiple failed logins , Detecting port scanning activity', 'Alarm system for cyberattacks.', '侵入を検知して警告', false),
  (28, 1, 'IoT (Internet of Things)', '', 'A network of physical devices (not just computers) connected to the internet.', 'モノのインターネット (もののインターネット)', 'Used to collect data, enable remote control, and automate physical objects.', ', Smart thermostat adjusting temperature remotely , Fitbit tracking health data to phone , Factory sensors predicting machine failure', 'Internet-connected everyday objects.', 'モノをネットに繋ぐ', false),
  (29, 1, 'IPS (Intrusion Prevention System)', '', 'A security system that detects AND blocks suspicious network activity in real-time.', '不正侵入を検知して遮断するシステム (いんたんじょんおう)', 'Used in corporate networks to actively stop attacks, placed inline with traffic flow.', ', Blocking known attack signatures , Dropping malicious packets , Preventing SQL injection attempts', 'Detect + block attacks in real-time.', '侵入を検知して防ぐ', false),
  (30, 1, 'IP Address (Internet Protocol Address)', '', 'A unique numeric label assigned to each device on a network for identification and location.', 'ネットワーク上の機器を識別する番号 (アイピーアドレス)', 'Used to route data between devices on the internet or local networks.', ', 192.168.1.1 for home router , IPv4 like 203.0.113.5 , IPv6 like 2001:db8::1', 'Phone number for devices on a network.', '機器のネットワーク住所', false),
  (31, 2, 'IrDA (Infrared Data Association)', '', 'A standard for wireless data transfer using infrared light, requiring line of sight.', '赤外線を使った近距離無線通信規格 (インフラレッド)', 'Used for short-range communication between devices like old phones, laptops, and printers.', ', Beaming contacts between old phones , Printing from PDA to printer , Wireless file transfer on legacy laptops', 'Line-of-sight infrared wireless.', '赤外線の通信規格', false),
  (32, 2, 'ISMS (Information Security Management System)', '', 'A systematic approach to managing sensitive company information and ensuring security.', '情報セキュリティを管理する仕組み (アイエスエムエス)', 'Used to establish security policies, procedures, and controls, often certified under ISO 27001.', ', Company-wide security policy implementation , Risk assessment for data breaches , ISO 27001 certification process', 'System for info security management.', 'セキュリティ管理の仕組み', false),
  (33, 2, 'ISO (International Organization for Standardization)', '', 'An international body that develops and publishes standards for various industries.', '国際標準化機構 (こくさいひょうじゅんかきこう)', 'Used to certify products and management systems for quality, safety, and efficiency.', ', ISO 9001 for quality management , ISO 27001 for security , ISO 14001 for environment', 'Global standards organization.', '国際規格を決める組織', false),
  (34, 2, 'ISO14000', '', 'A family of standards for environmental management systems.', '環境マネジメントに関する国際規格群 (ISO14000)', 'Used by organizations to reduce environmental impact and comply with regulations.', ', Factory waste reduction certification , Company carbon footprint measurement , Environmental compliance audit', 'Environmental management standards.', '環境管理の国際規格', false),
  (35, 2, 'ISO27000', '', 'A family of standards for information security management systems (ISMS).', '情報セキュリティ管理の国際規格群 (ISO27000)', 'Used to certify that an organization has proper security controls in place.', ', Data center security certification , Cloud service provider compliance , Bank information security audit', 'Information security standards family.', 'セキュリティ管理の規格群', false),
  (36, 2, 'ISO9000', '', 'A family of standards for quality management systems.', '品質マネジメントの国際規格群 (ISO9000)', 'Used to ensure consistent product and service quality across organizations.', ', Manufacturing quality control certification , Hospital patient care standards , Airline service quality management', 'Quality management standards.', '品質管理の国際規格', false),
  (37, 2, 'ITIL (Information Technology Infrastructure Library)', '', 'A framework of best practices for IT service management (ITSM).', 'ITサービス管理のベストプラクティス集 (アイティル)', 'Used by IT departments to align IT services with business needs, handle incidents, and manage changes.', ', Setting up a service desk , Managing IT changes without downtime , Incident response workflow design', 'Best practices for IT service.', 'IT運用のベストプラクティス', false),
  (38, 2, 'ITガバナンス (IT Governance)', '', 'A framework for ensuring IT investments support business goals and manage risks.', 'ITを戦略的に統制する仕組み (ITガバナンス)', 'Used by boards and executives to align IT with strategy, measure performance, and comply with regulations.', ', IT steering committee approving projects , Cybersecurity risk reporting to board , IT budget and ROI tracking', 'Control system for company IT.', 'ITの会社統治', false),
  (39, 2, 'KJ法 (KJ Method)', '', 'A creative brainstorming technique where ideas are written on cards, grouped, and organized.', 'カードに書いた情報を整理して新しい考えを生む方法 (KJほう)', 'Used in planning, problem-solving, and research to make sense of complex information.', ', New product brainstorm workshop , Customer feedback organization , Strategic planning sessions', 'Card sorting for idea organization.', 'カードで情報を整理', false),
  (40, 2, 'M＆A (Mergers and Acquisitions)', '', 'The process of companies combining (merger) or one buying another (acquisition).', '企業の合併と買収 (エムアンドエイ)', 'Used to grow market share, enter new markets, acquire technology, or eliminate competition.', ', Disney buying Pixar , Microsoft acquiring Activision Blizzard , Two banks merging into one', 'Companies joining or buying each other.', '企業の合併・買収', false),
  (41, 2, 'MACアドレス (MAC Address)', '', 'A unique hardware identifier assigned to network interfaces like Wi-Fi or Ethernet cards.', 'ネットワーク機器に固有の製造番号 (マックアドレス)', 'Used to identify devices on a local network and for MAC filtering in Wi-Fi security.', ', Router assigning fixed IP by MAC , MAC address whitelisting for office Wi-Fi , Device tracking in network management', 'Hardware serial number for network.', 'ネットワーク機器の個体番号', false),
  (42, 2, 'MBO (Management by Objectives)', '', 'A management system where managers and employees set shared goals together.', '目標による管理 (もくひょうによるかんり)', 'Used to align individual performance with company objectives through regular goal reviews.', ', Setting quarterly OKRs with team , Annual performance review by goal completion , Sales team revenue targets', 'Manage by shared goal setting.', '目標を決めて管理する手法', false),
  (43, 2, 'MP3', '', 'A digital audio coding format that compresses sound without significant quality loss.', '音声を圧縮するデジタル形式 (エムピースリー)', 'Used for music streaming, storage, and sharing across devices and platforms.', ', Spotify streaming in MP3 , iPhone music library , Podcast audio files', 'Compressed music file format.', '音楽圧縮の標準形式', false),
  (44, 2, 'MRP (Material Requirements Planning)', '', 'A system for calculating raw material needs based on production schedules and inventory.', '生産計画に基づいて資材を計算するシステム (エムアールピー)', 'Used in manufacturing to ensure materials are available for production and minimize inventory costs.', ', Car factory ordering parts just in time , Electronics assembly line planning , Food production ingredient ordering', 'Calculate what materials to buy and when.', '資材所要量の計画', false),
  (45, 2, 'MTBF (Mean Time Between Failures)', '', 'The average time between failures of a repairable system or component.', '平均故障間隔 (へいきんこしょうかんかく)', 'Used to measure reliability and predict how often a device will fail.', ', Hard drive reliability rating (e.g., 1M hours) , Car engine durability comparison , Industrial machine maintenance scheduling', 'Average time between breakdowns.', '故障から次の故障までの時間', false),
  (46, 2, 'MTTR (Mean Time To Repair)', '', 'The average time needed to repair a failed system or component.', '平均修復時間 (へいきんしゅうふくじかん)', 'Used to measure maintainability and estimate how long systems will be down after failure.', ', Server repair time target (e.g., 4 hours) , Elevator breakdown recovery SLA , Factory machine maintenance response', 'Average time to fix after failure.', '修理にかかる平均時間', false),
  (47, 2, 'NDA (Non-Disclosure Agreement)', '', 'A legal contract that protects confidential information from being shared.', '秘密保持契約 (ひみつほじけいやく)', 'Used before sharing business secrets, customer data, or intellectual property with partners or employees.', ', Employee signing at hire , Partner discussing a new product , Consultant accessing financial data', 'Legal promise to keep secrets.', '秘密を守る契約書', false),
  (48, 2, 'OEM (Original Equipment Manufacturer)', '', 'A company that makes parts or products that another company sells under its own brand.', '他社ブランドで販売する製品を製造する会社 (オーイーエム)', 'Used to produce goods without building factories, letting brands focus on marketing and sales.', ', Foxconn making iPhones for Apple , Samsung making screens for other brands , Generic laptops sold as store brands', 'Make product for another''s brand.', '他社ブランドで生産', false),
  (49, 2, 'Off-JT (Off-the-Job Training)', '', 'Training that takes place away from the regular work environment, like classrooms or workshops.', '職場を離れて行う研修 (オフザジョブトレーニング)', 'Used to teach theoretical knowledge, soft skills, or certifications without work distractions.', ', Leadership workshop offsite , Programming bootcamp course , Safety certification class', 'Training outside the workplace.', '職場外での研修', false),
  (50, 2, 'OJT (On-the-Job Training)', '', 'Training that takes place at the actual workplace while performing real tasks.', '職場で実際の仕事をしながら行う研修 (オンジョブトレーニング)', 'Used to learn practical skills directly applicable to daily work with supervisor guidance.', ', New cashier learning register with mentor , Junior developer fixing real bugs , Apprentice learning from senior chef', 'Learning while working.', '実務を通じた研修', false),
  (51, 2, 'OSS (Open Source Software)', '', 'Software with source code freely available for use, modification, and distribution.', 'ソースコードが公開されているソフトウェア (オープンソースソフトウェア)', 'Used by developers to build applications without starting from scratch, saving time and cost.', ', Linux operating system , Apache web server , LibreOffice productivity suite', 'Free software with visible code.', 'ソースコードが開かれたソフト', false),
  (52, 2, 'PDCAサイクル (PDCA Cycle)', '', 'A continuous improvement cycle: Plan, Do, Check, Act.', '計画・実行・評価・改善を繰り返す手法 (ピーディーシーエーサイクル)', 'Used in quality management, project management, and personal productivity.', ', Manufacturing quality control , Marketing campaign optimization , Personal habit improvement', 'Plan → Do → Check → Act loop.', '計画・実行・評価・改善の繰り返し', false),
  (53, 2, 'PDF (Portable Document Format)', '', 'A file format that preserves document layout and fonts across all devices.', 'レイアウトが変わらない電子文書形式 (ピーディーエフ)', 'Used for sharing documents that need exact formatting, like contracts, invoices, and ebooks.', ', Sending a resume as PDF , Ebook distribution , Bank statement archiving', 'Fixed-layout document format.', 'レイアウト固定の文書形式', false),
  (54, 2, 'PKI (Public Key Infrastructure)', '', 'A system for managing digital certificates and encryption keys for secure communication.', '公開鍵暗号のための基盤システム (ピーケーアイ)', 'Used to enable HTTPS, email encryption, and digital signatures across the internet.', ', SSL/TLS certificates for websites , Government digital ID cards , Company VPN authentication', 'System for digital keys and certificates.', '電子証明書の運用基盤', false),
  (55, 2, 'PLC (Product Life Cycle)', '', 'The stages a product goes through: Introduction, Growth, Maturity, Decline.', '製品の市場での生涯サイクル (プロダクト・ライフ・サイクル)', 'Used to plan marketing strategy, pricing, and product updates based on lifecycle stage.', ', iPhone: growth to maturity , Fax machines: decline stage , New EV: introduction stage', 'Stages: intro → growth → mature → decline.', '製品の寿命サイクル', false),
  (56, 2, 'PL法 (Product Liability Act)', '', 'A law that holds manufacturers responsible for injuries caused by defective products.', '製品の欠陥で被害が出た場合に製造業者の責任を問う法律 (プロダクト・ライアビリティほう)', 'Used by consumers to sue for damages from defective cars, appliances, food, or medicine.', ', Airbag defect recall lawsuit , Food poisoning from contaminated product , Toy choking hazard claim', 'Manufacturer pays for product defects.', '製品欠陥の製造者責任', false),
  (57, 2, 'PMBOK (Project Management Body of Knowledge)', '', 'A guide covering standard terminology and best practices in project management.', 'プロジェクトマネジメントの知識体系 (ピーボック)', 'Used by project managers to follow standard processes across industries like IT, construction, and events.', ', PMP certification exam preparation , Software project planning , Construction project scheduling', 'Project management standard guide.', 'プロジェクト管理の標準知識', false),
  (58, 2, 'POSシステム (POS System)', '', 'A system that records sales transactions at checkout and updates inventory in real-time.', '販売時点情報管理システム (ポスシステム / はんばいじてんてんじょうほう)', 'Used in retail stores, restaurants, and hotels to process payments and track sales data.', ', 711 cash register tracking inventory , Restaurant tablet ordering system , Self-checkout at supermarket', 'Register that tracks sales and stock.', 'レジ＋在庫管理システム', false),
  (59, 2, 'PPM (Product Portfolio Management)', '', 'A method to manage a company''s products based on market growth and market share (BCG matrix).', '製品ポートフォリオ管理 (プロダクト・ポートフォリオ・マネジメント)', 'Used to decide which products to invest in, maintain, or phase out.', ', BCG matrix: Stars, Cash Cows, Question Marks, Dogs , Car company deciding to kill a slow-selling model , Tech firm funding new flagship product', 'Manage products like an investment portfolio.', '製品を投資で管理する手法', false),
  (60, 2, 'RAIDシステム (RAID System)', '', 'A technology that combines multiple hard drives together for performance, redundancy, or both.', '複数のディスクをまとめて使う技術 (レイドシステム)', 'Used in servers and storage systems to prevent data loss from a single disk failure.', ', RAID 1: mirroring for safety , RAID 5: striping with parity , Server with 4 drives in RAID 10', 'Multiple disks acting as one for safety or speed.', '複数ディスクを統合する技術', false),
  (61, 3, 'スパイラルモデル (Spiral Model)', '', 'A software development model combining prototyping and waterfall with a focus on risk analysis in iterative cycles.', 'リスク分析を重視し、螺旋状に繰り返しながら開発を進めるモデル (スパイラルモデル)', 'Used for large, complex, high-risk projects where requirements are unclear.', ', NASA space system development , Large-scale government IT project , Medical device software', 'Risk-driven iterative development loop.', 'リスク分析を繰り返す開発手法', false),
  (62, 3, 'スプーリング (Spooling)', '', 'A process that holds data temporarily in a buffer (like memory or disk) while a slower device, like a printer, catches up.', '低速な周辺機器のためにデータを一時的に蓄積する仕組み (スプーリング)', 'Used to free up the CPU so it doesn''t have to wait for slower I/O devices.', ', Sending multiple documents to a network printer , Reading data from a CD-ROM while playing music , Input from a keyboard to the CPU', 'Buffering data for slow devices.', '低速機器のための一時データ蓄積', false),
  (63, 3, 'スループット (Throughput)', '', 'The amount of work or data a system processes successfully over a given period of time.', '単位時間あたりに処理できる仕事量 (スループット)', 'Used to measure performance of networks, CPUs, assembly lines, etc.', ', Network: 100 Mbps data transfer , Factory: 500 cars per day , Server: 10,000 requests/minute', 'Actual work done per unit time.', '単位時間あたりの処理量', false),
  (64, 3, 'ターンアラウンドタイム (Turnaround Time)', '', 'The total time between submitting a job to a system and receiving the completed result.', '処理を依頼してから結果を受け取るまでの総時間 (ターンアラウンドタイム)', 'Used in batch processing, user experience, and operational efficiency.', ', Time to compile and run a program , Time from laundry drop-off to pickup , Time from order to product delivery', 'Request-to-result total time.', '依頼から完了までの全時間', false),
  (65, 3, 'チェックディジット (Check Digit)', '', 'An extra digit added to a number to detect common data entry errors like typos or digit swaps.', '入力ミスを検出するために追加される数字 (チェックディジット)', 'Used in barcodes, credit card numbers, and identification codes.', ', UPC barcode on products , ISBN number on books , Credit card number validation', 'Error-detecting extra digit.', '入力誤り発見のための数字', false),
  (66, 3, '著作権 (Copyright)', '', 'A legal right giving the creator of original work exclusive rights to its use and distribution for a limited time.', '著作物を保護する法律上の権利 (ちょさくけん)', 'Used to control copying, public performance, and adaptation of creative works.', ', Music on Spotify not free to download , Movie not allowed to record in theater , Software license terms', 'Creator controls the work legally.', '創作物を守る権利', false),
  (67, 3, 'ディジタルデバイド (Digital Divide)', '', 'The gap between those who have access to modern information technology and those who do not.', '情報技術を利用できる人とできない人の差 (ディジタルデバイド)', 'Used in social policy to address inequality in internet access and digital literacy.', ', Urban vs rural broadband access , Elderly struggling with online banking , Low-income students without laptops', 'Technology access gap.', 'IT利用の格差問題', false),
  (68, 3, 'データウェアハウス (Data Warehouse)', '', 'A large, centralized storage system that collects data from multiple sources for analysis and reporting.', '分析用に複数のデータ源から集めた大規模データベース (データウェアハウス)', 'Used by businesses for business intelligence, historical analysis, and data mining.', ', Amazon analyzing purchase history , Hospital aggregating patient records , Bank consolidating transaction data', 'Central data store for analysis.', '分析用の巨大データ倉庫', false),
  (69, 3, 'データマート (Data Mart)', '', 'A smaller, focused subset of a data warehouse designed for a specific team or department.', '特定の部署向けに作られた小規模なデータウェアハウス (データマート)', 'Used when a department needs quick access to tailored data without navigating the whole warehouse.', ', Sales team''s regional sales mart , Marketing campaign performance mart , Finance department budget mart', 'Department-sized data warehouse.', '部署専用のデータ小売店', false),
  (70, 3, 'データマイニング (Data Mining)', '', 'The process of discovering hidden patterns, correlations, and insights from large datasets.', '大量のデータから有益なパターンやルールを見つけること (データマイニング)', 'Used for market basket analysis, fraud detection, and customer segmentation.', ', Supermarket: beer & diapers together , Credit card company detecting fraud , Netflix recommending movies', 'Finding gold nuggets in data mountains.', 'データから価値ある情報を発掘', false),
  (71, 3, 'デジタル署名 (Digital Signature)', '', 'A cryptographic technique that proves the authenticity and integrity of a digital message or document.', '電子文書の作成者と改ざんされていないことを証明する技術 (デジタルしょめい)', 'Used for secure emails, software distribution, and legal contracts.', ', Signing a PDF contract online , Microsoft verifying driver updates , SSL certificate on website', 'Digital proof of who signed and no tampering.', '電子文書の本人確認と改竄防止', false),
  (72, 3, 'デジタルフォレンジックス (Digital Forensics)', '', 'The process of recovering and investigating data from digital devices, often for legal evidence.', '犯罪捜査の証拠としてデジタル機器からデータを復元・分析する技術 (デジタルフォレンジックス)', 'Used in criminal investigations, corporate internal investigations, and incident response.', ', Recovering deleted files from a hard drive , Tracing a hacker''s network activity , Investigating employee data theft', 'CSI for computers and phones.', 'デジタル機器の法科学的調査', false),
  (73, 3, 'デファクトスタンダード (De Facto Standard)', '', 'A standard that becomes widely adopted by market popularity, not because it''s officially approved by a standards body.', '公式な規格ではなく、市場でよく使われるようになった事実上の標準 (デファクトスタンダード)', 'Used to describe technologies that won the market battle.', ', Microsoft Office file formats (.doc, .xls) , PDF by Adobe , Qwerty keyboard layout', 'Market-chosen winner standard.', '業界の事実上の標準', false),
  (74, 3, 'デュアルシステム (Dual System)', '', 'A fault-tolerant system where two independent computer systems run the same job, and their outputs are compared.', '同じ処理を二つの独立したシステムで実行し、結果を照合する方式 (デュアルシステム)', 'Used in critical applications where errors are unacceptable, like financial or aerospace systems.', ', Airline reservation system , Stock exchange transaction matching , Nuclear reactor control system', 'Two computers, one result (checking each other).', '結果を照合する二重システム', false),
  (75, 3, 'デュプレックスシステム (Duplex System)', '', 'A system with two identical components where one is active and the other is on standby, ready to take over if the primary fails.', '現用系と待機系を持ち、故障時に切り替えるシステム (デュプレックスシステム)', 'Used to ensure high availability for critical servers and networks.', ', Primary and backup web server , Standby database server ready to take over , Dual power supply in a server', 'Active + Standby for no downtime.', '予備機で高可用性を実現', false),
  (76, 3, '電子商取引 (EC) (Electronic Commerce)', '', 'Buying and selling goods or services using the internet and digital transactions.', 'インターネットを介した商品やサービスの売買 (でんししょうとりひき / イーシー)', 'Used for online retail, digital payments, and online marketplaces.', ', Amazon shopping for clothes , Buying train tickets on a website , Paying for a subscription with PayPal', 'Doing business online.', 'インターネットでの売買', false),
  (77, 3, '特許権 (Patent Right)', '', 'An exclusive right granted for an invention, preventing others from making, using, or selling it without permission.', '発明を独占的に利用できる権利 (とっきょけん)', 'Used to protect new technologies, drugs, and processes for a limited time (typically 20 years).', ', iPhone''s unique design patent , Pharmaceutical drug formula , Tesla''s electric vehicle battery patent', 'Inventor''s exclusive monopoly for a time.', '発明を独占する権利', false),
  (78, 3, 'ナレッジマネジメント (Knowledge Management)', '', 'The systematic process of capturing, distributing, and using knowledge within an organization.', '組織内の知識を共有し活用するための管理手法 (ナレッジマネジメント)', 'Used to prevent reinventing the wheel and retain expertise when employees leave.', ', Company wiki for internal documentation , Lessons learned database after projects , Expert directory to find specialists', 'Not losing what your company knows.', '組織の知恵を貯めて活かす', false),
  (79, 3, 'バイオメトリクス認証 (Biometrics Authentication)', '', 'Automatic identification of a person based on their unique physical or behavioral traits.', '体の特徴を使って本人を確認する技術 (バイオメトリクスにんしょう)', 'Used for security access, device unlocking, and identity verification.', ', iPhone Touch ID (fingerprint) or Face ID , Airport immigration e-gates , Office door fingerprint scanner', 'You are the password.', '体の特徴で本人確認', false),
  (80, 3, 'パイプライン制御 (Pipeline Control)', '', 'A CPU technique where multiple instructions are overlapped in execution to improve processing speed.', 'CPUが命令を並行して処理する技術 (パイプラインせいぎょ)', 'Used in all modern processors to improve performance.', ', A washing machine: wash, rinse, spin overlap , Car factory assembly line , CPU executing fetch-decode-execute in stages', 'Assembly line for computer instructions.', '命令を段階的に並列処理', false),
  (81, 3, 'ハウジングサービス (Housing Service)', '', 'A service where a customer places their own server in a provider''s data center, providing power, cooling, and network.', '自社のサーバをデータセンターに預けて運用するサービス (ハウジングサービス)', 'Used by companies that want to own hardware but avoid building their own data center.', ', Colocation at Equinix data center , Small business hosting own server , Web company renting rack space', 'Rent physical space for your own server.', '自前サーバを預けて運用', false),
  (82, 3, '派遣契約 (Temporary Staffing Contract)', '', 'A contract where a staffing agency employs a worker and sends them to work temporarily at a client company.', '人材派遣会社が労働者を雇い、他の会社に派遣する契約 (はけんけいやく)', 'Used to fill temporary skill gaps, cover parental leave, or manage seasonal workload.', ', IT specialist for 3-month project , Receptionist covering sick leave , Warehouse worker for holiday season', 'You work for agency, report to client.', '派遣会社が労働者を送り込む契約', false),
  (83, 3, 'バリアフリー (Barrier-free)', '', 'Design that eliminates physical obstacles to enable access for people with disabilities, elderly, or other mobility issues.', '障害や年齢に関わらず利用しやすい環境を作る考え方 (バリアフリー)', 'Used in architecture, product design, and public transportation.', ', Wheelchair ramps on sidewalks , Tactile paving for the blind , Closed captions on videos', 'Removing obstacles for all people.', '障害となるものを取り除く', false),
  (84, 3, 'バリューチェーン (Value Chain)', '', 'A model that breaks down a company''s activities into primary and support activities that add value to the final product.', '製品やサービスに価値が付加される一連の企業活動 (バリューチェーン)', 'Used to analyze where a company can reduce costs or differentiate itself.', ', Starbucks: bean sourcing, roasting, store experience , Amazon: order, pick, pack, ship , Toyota: design, parts, assembly, service', 'Steps from raw material to customer value.', '価値が生まれる活動の連鎖', false),
  (85, 3, 'パレート図・ABC分析 (Pareto Chart / ABC Analysis)', '', 'A chart showing bars in descending order with a cumulative line, based on the 80/20 rule (80% effects come from 20% causes).', '少数の要因が全体の大部分を占めるという分析手法 (パレートず / ABCぶんせき)', 'Used in quality control, inventory management, and to prioritize problems.', ', 80% of sales from 20% of products , 80% of complaints from 20% of issue types , A-items (high value) vs C-items (low value) in inventory', 'Focus on the vital few, not the trivial many.', '2割の要因で8割の結果を説明', false),
  (86, 3, 'ファイアウォール (Firewall)', '', 'A network security system that monitors and controls incoming and outgoing traffic based on predetermined rules.', 'ネットワークの出入り口で通信を監視し遮断するシステム (ファイアウォール)', 'Used to protect internal networks from unauthorized external access.', ', Home router blocking suspicious IPs , Office network blocking social media , Cloud firewall protecting web server', 'Wall between internal network and internet.', 'ネットワークの出入り口番', false),
  (87, 3, 'ファシリティマネジメント (Facility Management)', '', 'The management of buildings, infrastructure, and real estate to support an organization''s core operations.', '建物や設備を最適に管理する業務 (ファシリティマネジメント)', 'Used to reduce operating costs, ensure safety, and improve workspace efficiency.', ', Office cleaning and maintenance , Energy management for a building , Space planning for remote/hybrid work', 'Taking care of all buildings and property.', '施設・設備の総合管理', false),
  (88, 3, 'ファブレス (Fabless)', '', 'A company that designs and sells hardware but outsources the actual manufacturing (fabrication).', '自社で製造工場を持たず、設計だけを行う企業戦略 (ファブレス)', 'Used in semiconductor industry to focus on chip design and avoid multi-billion dollar fab costs.', ', NVIDIA designing GPUs, TSMC manufacturing , Apple designing chips, TSMC making them , ARM licensing designs to producers', 'Design only, no factories.', '工場を持たない製造業', false),
  (89, 3, 'フールプルーフ (Foolproof)', '', 'A design principle that makes it impossible to make mistakes, even if the user is careless or untrained.', '操作を間違えようとしても間違えられないように設計すること (フールプルーフ)', 'Used in safety-critical products, consumer goods, and industrial equipment.', ', USB plug that only fits one way (now) , Microwave won''t run with door open , Gas pump auto shut-off when tank full', 'Design against user stupidity.', 'バカでも間違えられない設計', false),
  (90, 3, 'フェールセーフ (Fail-safe)', '', 'A design principle where a system defaults to a safe state when it fails, rather than causing damage or injury.', '故障時に安全な状態に自動的に移行する設計 (フェールセーフ)', 'Used in elevators, traffic lights, trains, and industrial machinery.', ', Elevator brakes engage when cable fails , Traffic lights turn red flashing on power loss , Train doors close automatically if power fails', 'When broken, go to safe mode, not dangerous.', '壊れても安全側に倒れる', false),
  (91, 4, 'フェールソフト (Fail-soft)', '', 'A design where a system continues to operate at a reduced capacity after failure, rather than completely stopping.', '一部が故障しても全体は停止せず、能力を落として続行する設計 (フェールソフト)', 'Used in critical servers, networks, and services where some function is better than none.', ', Printer works in slow mode after paper jam sensor fails , Web server shows read-only mode if database fails , Phone works only for emergency calls if battery low', 'Fail, but keep working a bit.', '故障しても機能縮小で継続', false),
  (92, 4, 'フォールトアボイダンス (Fault Avoidance)', '', 'A strategy to prevent faults from occurring during development by using high-quality components and rigorous design.', '開発段階で障害の発生を防ぐ品質対策 (フォールトアボイダンス)', 'Used in high-reliability systems like aerospace and medical devices.', ', Using military-grade components , Extreme testing before launch (NASA) , Coding with formal verification methods', 'Stop faults before they exist.', '故障を最初から作らない対策', false),
  (93, 4, 'フォールトトレラント (Fault Tolerant)', '', 'A system''s ability to continue operating correctly even when one or more components fail.', '一部の部品が故障してもシステム全体は正常に動き続ける性質 (フォールトトレラント)', 'Used in critical systems like servers, aircraft, and spacecraft.', ', Airliner with 4 engines can fly with 1 failed , Server RAID with two disks , Spacecraft redundant navigation systems', 'Keep going correctly even when parts break.', '部品が壊れても動き続ける', false),
  (94, 4, 'フォワードエンジニアリング (Forward Engineering)', '', 'The traditional software development process of going from high-level specifications to actual system implementation.', '設計から実装へ進む伝統的な開発プロセス (フォワードエンジニアリング)', 'Used in standard software development when starting from scratch.', ', Writing code from requirements document , Building a house from blueprints , Creating a database from ER diagram', 'Traditional design-then-build approach.', '仕様からコードを作る手法', false),
  (95, 4, '不正アクセス禁止法 (Unauthorized Computer Access Act)', '', 'A Japanese law that prohibits unauthorized access to computer systems and punishes hacking activities.', '他人のコンピュータに無断でアクセスする行為を禁止する法律 (ふせいアクセスきんしほう)', 'Used in Japan to prosecute hackers, ID thieves, and those sharing illegal login credentials.', ', Sharing someone else''s password , Guessing another person''s login ID , Accessing server without permission', 'Japan''s anti-hacking law.', '不正なコンピュータアクセスを罰する法', false),
  (96, 4, '不正競争防止法 (Unfair Competition Prevention Act)', '', 'A Japanese law that protects trade secrets and prevents unfair business practices like false claims, trademark infringement, and misappropriation.', '商標侵害や営業秘密の盗用など、不正な競争行為を禁止する法律 (ふせいきょうそうぼうしほう)', 'Used to protect intellectual property and fair market competition.', ', Stealing customer list from former employer , Fake luxury bags sold as real , Copying a competitor''s product design', 'Stop dirty business tricks.', '不正な競争手段を禁止する法', false),
  (97, 4, 'プラグアンドプレイ (Plug and Play)', '', 'A technology that automatically detects and configures a new device when connected to a computer, without manual driver installation.', '周辺機器を接続するだけで使える技術 (プラグアンドプレイ)', 'Used for USB devices, monitors, printers, and external drives.', ', Plugging in a USB mouse - it just works , Connecting a monitor via HDMI , Inserting an SD card', 'Connect and use immediately.', '繋げばすぐに使える機能', false),
  (98, 4, 'フラグメンテーション (Fragmentation)', '', 'The inefficient use of storage space where free space is broken into small, non-contiguous blocks over time.', 'ファイルの削除や作成を繰り返すことで記憶領域が細切れになる現象 (フラグメンテーション)', 'Occurs in file systems and memory, slowing down access speeds.', ', PC getting slower over time due to many writes , Hard drive needing defragmentation , Memory fragmentation causing app crashes', 'Storage space scattered like puzzle pieces.', '記憶領域の断片化', false),
  (99, 4, 'ブラックボックステスト (Black-box Testing)', '', 'Software testing where the internal structure is not known; testers provide inputs and check outputs against requirements.', '内部構造を見ずに入力と出力だけでテストする手法 (ブラックボックステスト)', 'Used in acceptance testing, system testing, and by end-user testers.', ', Testing login: correct pass → success, wrong pass → error , Checking calculator app: 2+2=4 , Testing a website without knowing its code', 'Test from outside, like a user.', '内部を見ずに機能テスト', false),
  (100, 4, 'フラッシュメモリ (Flash Memory)', '', 'A non-volatile memory that retains data without power, used for storage in USB drives and SSDs.', '電源が切れてもデータを保持できるメモリ技術 (フラッシュメモリ)', 'Used in USB drives, SD cards, solid-state drives (SSD), and smartphones.', ', SanDisk USB stick , MicroSD card for phone storage , Laptop SSD', 'Storage that keeps data when off.', '電源オフでも記憶を保持', false),
  (101, 4, 'ブルーオーシャン戦略 (Blue Ocean Strategy)', '', 'A strategy to create a new, uncontested market space (blue ocean) rather than competing in an existing crowded market (red ocean).', '競争のない新しい市場を創造する経営戦略 (ブルーオーシャンせんりゃく)', 'Used when companies want to escape fierce competition and make competition irrelevant.', ', Cirque du Soleil (no animals, no stars) , Nintendo Wii (motion controls) , Yellow Tail wine (simple, fun wine)', 'Swim where no competitors exist.', '競争のない新市場を作れ', false),
  (102, 4, 'ブレーンストーミング (Brainstorming)', '', 'A creative group technique where participants generate many ideas without criticism, then evaluate them later.', '批判を禁止して自由にアイデアを出す会議手法 (ブレーンストーミング)', 'Used in product development, problem-solving, and creative planning.', ', Post-it note session for new feature ideas , Weekly team creative meeting , Advertising campaign idea generation', 'No judgment, just lots of ideas first.', 'とにかく沢山アイデアを出す会議', false),
  (103, 4, 'プロトタイプモデル (Prototype Model)', '', 'A software development approach where a working model is built early to refine requirements and get user feedback.', '試作品を作ってから本開発に入るモデル (プロトタイプモデル)', 'Used when requirements are unclear or user interface is critical.', ', Building a clickable app mockup for user testing , Showcasing a car clay model before production , Figma prototype for website approval', 'Build a rough model first to learn.', '試作→評価→完成を繰り返す', false),
  (104, 4, 'プロバイダ責任制限法 (Provider Liability Limitation Act)', '', 'A Japanese law that limits the legal liability of internet service providers for content posted by users, as long as they follow removal procedures.', 'プロバイダが利用者の投稿による損害賠償責任を負わない条件を定めた法律 (プロバイダせきにんせいげんほう)', 'Used to balance free speech and victim protection online.', ', ISP not liable for defamatory user comments unless they refuse removal , Facebook''s content moderation policies , 2ch (5channel) comment liability rules', 'ISP not responsible if they remove bad content.', 'プロバイダの責任を制限する法', false),
  (105, 4, 'ベンチマーキング (Benchmarking)', '', 'The practice of comparing your business processes and performance metrics to industry best practices or competitors.', '自社の製品やサービスを他社や業界標準と比較評価すること (ベンチマーキング)', 'Used to identify areas for improvement and set performance targets.', ', Airline comparing on-time performance against Delta , Restaurant comparing customer satisfaction to McDonald''s , Laptop speed compared to competitors', 'Measure yourself against the best.', '他社と比較して評価する', false),
  (106, 4, 'ホスティングサービス (Hosting Service)', '', 'A service that provides server space, computing power, or infrastructure to host websites or applications.', 'Webサイトやアプリを公開するためのサーバスペースを提供するサービス (ホスティングサービス)', 'Used by individuals and companies to make their websites accessible on the internet.', ', Bluehost for WordPress site , AWS EC2 for custom application , GitHub Pages for static site', 'Rent space for your website.', 'Web公開のためのサーバ貸出', false),
  (107, 4, 'ホワイトボックステスト (White-box Testing)', '', 'Software testing where the internal code structure is visible to the tester, allowing testing of paths, branches, and logic.', '内部構造を見てテストケースを作る手法 (ホワイトボックステスト)', 'Used by developers for unit testing and finding hidden errors.', ', Testing every if-else branch in code , Checking a loop runs exactly N times , Unit testing with code coverage tool', 'Test knowing the code inside.', '内部構造を考慮したテスト', false),
  (108, 4, 'マーケティング (Marketing) (Target', '', 'One-to-one), Activities to promote and sell products', '', 'including target marketing (segmenting audiences) and one-to-one marketing (personalizing to individuals). JP: 顧客に合わせた販売促進活動 (マーケティング),Used to identify customer needs and deliver personalized value.,・Amazon personalized recommendations ・Email with your name and past purchases ・Ads showing shoes you browsed,EN: Right product to right person at right time. JP: 顧客一人ひとりに合わせた販売', '', '', '', false),
  (109, 4, 'マイルストーン (Milestone)', '', 'A significant checkpoint or event in a project timeline that marks the completion of a major phase.', 'プロジェクトの重要な節目や段階を表す目印 (マイルストーン)', 'Used in project management to track progress and manage deadlines.', ', Project Kickoff (Milestone 1) , Alpha Version Complete (Milestone 2) , Final Delivery (Milestone 3)', 'Big checkpoints along the project road.', 'プロジェクトの重要な節目', false),
  (110, 4, 'メーリングリスト (Mailing List)', '', 'A group of email addresses used to send a single message to many recipients simultaneously.', '同じメッセージを複数の受信者に同時送信するための仕組み (メーリングリスト)', 'Used for team announcements, newsletters, and discussion groups.', ', Company all-employees list , Classroom announcements to parents , Open source project developers list', 'One email to many people.', '同時に複数人へメール配信', false),
  (111, 4, 'メモリインタリーブ (Memory Interleaving)', '', 'A technique that splits memory into multiple banks so the CPU can access them simultaneously, increasing speed.', 'メモリを複数の独立した区画に分けて並列アクセスする技術 (メモリインタリーブ)', 'Used in high-performance computing and gaming systems.', ', Dual-channel RAM on motherboards , Graphics card memory design , Supercomputer memory architecture', 'Access multiple memory sections at once.', '複数メモリを同時に読み書き', false),
  (112, 4, '問題管理 (Problem Management)', '', 'The process of identifying and eliminating the root causes of recurring incidents to prevent future disruptions.', '繰り返し発生する障害の根本原因を特定し、再発を防止する管理プロセス (もんだいかんり)', 'Used in IT service management (ITIL) to reduce ticket volume and improve system stability.', ', Analyzing why servers crash every Tuesday , Fixing a bug causing login failures , Replacing faulty network cables causing drops', 'Stop problems from coming back (root cause fix).', '繰り返す障害の根本対策', false),
  (113, 4, 'ユーザビリティ (Usability)', '', 'The ease of use and learnability of a product or system from the user''s perspective.', '製品やシステムの使いやすさ (ユーザビリティ)', 'Used in web design, app development, and product design.', ', Website with clear menu and search , App that can be used one-handed , Remote control with logical button layout', 'How easy something is to use.', '使いやすさの度合い', false),
  (114, 4, 'ユニバーサルデザイン (Universal Design)', '', 'The design of products and environments to be usable by all people, regardless of age, ability, or status, without adaptation.', '年齢や能力に関わらず誰もが使いやすいように最初から設計する考え方 (ユニバーサルデザイン)', 'Used in architecture, product design, and public spaces.', ', Low-floor buses with ramp for everyone , Lever door handles (vs round knobs) , Curbs cuts for wheelchairs and strollers', 'Design for all people from the start.', '誰もが使いやすい設計', false),
  (115, 4, 'リスクマネジメント (Risk Management)', '', 'The systematic process of identifying, assessing, and mitigating risks to an organization.', 'リスクを特定し評価し対策する管理プロセス (リスクマネジメント)', 'Used in projects, finance, cybersecurity, and daily operations.', ', Cybersecurity: buy insurance, install firewall, train staff , Project: identify delay risks, add buffer time , Finance: diversify investments', 'Identify, assess, control risks.', 'リスクを洗い出し対策する管理', false),
  (116, 4, 'リバースエンジニアリング (Reverse Engineering)', '', 'The process of taking apart a product to understand its design, components, or code, often to recreate or analyze it.', '完成品を分解・解析して仕組みを理解する技術 (リバースエンジニアリング)', 'Used for malware analysis, legacy system recovery, and compatibility research.', ', Analyzing competitor''s product to learn how it works , Malware researcher disassembling virus code , Recovering lost source code from executable', 'Take it apart to figure how it was made.', '製品を解析して仕組みを解明', false),
  (117, 4, 'レスポンスタイム (Response Time)', '', 'The time between a user''s request and the system''s first response or completion of that request.', 'ユーザーの操作に対してシステムが反応するまでの時間 (レスポンスタイム)', 'Used to measure system performance and user experience.', ', Website loading after click , Search engine returning results , App opening from tap to display', 'Request → response duration.', '操作から反応までの時間', false),
  (118, 4, 'ロールバック (Rollback)', '', 'The process of reverting a system or database to a previous, consistent state after a failed transaction or error.', '失敗した処理を取り消し、前の状態に戻す処理 (ロールバック)', 'Used in database transactions, software updates, and version control.', ', Cancel online payment if credit card fails , Revert to older OS after bad update fails , Undo git push in GitHub', 'Undo changes to go back to safe point.', '直前の正しい状態まで戻す', false),
  (119, 4, 'ロールフォワード (Roll-forward)', '', 'The process of applying saved changes (logs) to a backup to bring a system to the most recent state after a failure.', 'バックアップに変更履歴を適用して最新状態に戻す復旧処理 (ロールフォワード)', 'Used in database recovery after a system crash.', ', Restoring database from morning backup then applying today''s transaction log , After power outage, applying recent changes to server , Recovery from transaction log', 'Bring backup forward to current time with logs.', 'ログを適用して最新状態に復元', false),
  (120, 4, 'ロングテール (Long Tail)', '', 'A business strategy where selling many low-demand niche products generates as much or more profit than selling a few bestsellers.', '売れ筋ではない多数の商品の総和が、ベストセラーと同じかそれ以上の売上になる戦略 (ロングテール)', 'Used by e-commerce and streaming services to profit from vast inventory of less popular items.', ', Amazon selling millions of obscure books , Netflix library of old and niche movies , Spotify''s deep catalog of indie music', 'Niche products in small quantities add up to big money.', 'ニッチ商品の集積が生む利益', false),
  (121, 5, 'BOT (Bot)', '', 'An automated software program that performs repetitive tasks over a network or on a device.', '自動で反復作業を行うプログラム (ボット)', 'Used for both good (search engines, customer service) and bad (spam, attacks).', ', Googlebot crawling websites , Chatbot answering customer questions , Twitter bot posting automated weather updates', 'Robot software that works automatically.', '自動動作するソフトウェア', false),
  (122, 5, 'DoS攻撃 (DoS Attack)', '', 'A cyberattack that overwhelms a server with fake traffic or requests, making it unavailable to real users.', 'サーバに大量のリクエストを送り機能停止させる攻撃 (ディーオーエスこうげき)', 'Used by hackers to shut down websites, online games, or services.', ', Flooding a bank website so no one can log in , Online game server becoming unplayable , Crashing a school''s registration system on enrollment day', 'Crash service with fake traffic flood.', '偽の通信でサービスを止める', false),
  (123, 5, 'IPスプーフィング (IP Spoofing)', '', 'A technique where an attacker alters packet headers to disguise their real IP address, pretending to be a trusted source.', '送信元IPアドレスを偽装する攻撃技術 (アイピースプーフィング)', 'Used in DDoS attacks, bypassing IP filters, and hiding identity.', ', Hacker making attack look like it comes from internal company network , Pretending to be a trusted partner server , Hiding location during a cyberattack', 'Fake return address on internet packages.', 'IPアドレスを詐称する技術', false),
  (124, 5, 'SQLインジェクション (SQL Injection)', '', 'An attack where malicious SQL code is inserted into a web form input to manipulate or steal database data.', 'Web入力フォームに悪意のあるSQLコードを挿入する攻撃 (SQLインジェクション)', 'Used to bypass login, steal customer data, or delete database tables.', ', Entering '' OR ''1''=''1 as password to bypass login , Stealing credit card numbers from e-commerce site , Deleting a database table via vulnerable search box', 'Trick database by typing code into a form.', '入力欄にSQLを忍び込ませる攻撃', false),
  (125, 5, 'ガンブラー (Gumblar)', '', 'A type of malware that steals FTP credentials and injects malicious JavaScript into web pages, infecting site visitors.', 'FTP情報を盗み、Webページに悪意のあるJavaScriptを挿入するマルウェア (ガンブラー)', 'Used to spread malware by compromising legitimate websites.', ', Infected website showing fake codec update , Injected script redirecting visitors to exploit kit , Website defacement via stolen credentials', 'Malware that turns websites into infection sources.', 'Webサイトを感染源に変えるマルウェア', false),
  (126, 5, 'キーロガー (Keylogger)', '', 'A type of malware that records every keystroke a user makes, capturing passwords, messages, and sensitive data.', 'キーボードの入力を全て記録するマルウェア (キーロガー)', 'Used by attackers to steal passwords, credit card numbers, and personal messages.', ', Recording typed passwords on a public computer , Capturing credit card number during online shopping , Logging chat messages for corporate espionage', 'Digital eavesdropper on your keyboard.', 'キーボード入力記録ソフト', false),
  (127, 5, 'クッキー (Cookie)', '', 'A small text file stored by a website on a user''s browser to remember stateful information like login status or preferences.', 'Webサイトがブラウザに保存する小さなテキストファイル (クッキー)', 'Used for authentication, shopping cart contents, language preferences, and tracking.', ', Staying logged into Gmail across visits , Amazon cart keeping items after closing browser , Website remembering dark mode preference', 'Website memory on your computer.', 'Webサイトの状態保存データ', false),
  (128, 5, 'クラッキング (Cracking)', '', 'Unauthorized breaking into computer systems or software, often with malicious intent (different from ethical hacking).', '悪意を持ってコンピュータシステムやソフトウェアに侵入・破壊行為をすること (クラッキング)', 'Used for data theft, vandalism, software piracy, or financial gain.', ', Removing software license check illegally , Breaking into a bank database to steal money , Defacing government websites', 'Malicious hacking for bad purposes.', '悪意のあるハッキング行為', false),
  (129, 5, 'クロスサイトスクリプティング (Cross-site Scripting / XSS)', '', 'An attack where malicious scripts are injected into trusted websites, then executed in victims'' browsers.', '悪意のあるスクリプトをWebサイトに埋め込み、閲覧者のブラウザで実行させる攻撃 (クロスサイトスクリプティング)', 'Used to steal cookies, session tokens, or redirect users to malicious sites.', ', Posting a comment with JavaScript that steals login cookies , Fake login form injected into banking page , Redirecting users to phishing site after clicking legitimate link', 'Evil code running inside trusted website.', 'Webサイトに悪意のコードを埋め込む', false),
  (130, 5, 'サラミ法 (Salami Slicing / Salami Technique)', '', 'A fraud technique where small, unnoticeable amounts of money are stolen from many transactions over time.', '一回あたりは少額の金銭を多くの取引から少しずつ盗む手口 (サラミほう)', 'Used in financial fraud and computer crime.', ', Rounding down interest calculations and stealing fractions of cents , Stealing 1 yen from millions of transactions , Skimming tiny amounts from ETF trades', 'Steal tiny slices that add up to a feast.', '少額をこっそり何度も盗む手口', false),
  (131, 5, '辞書攻撃 (Dictionary Attack)', '', 'A password cracking method that tries a list of common words and passwords (a dictionary) against a login system.', 'よく使われる単語やパスワードのリストを総当たりで試す攻撃方法 (じしょこうげき)', 'Used by attackers to break weak passwords quickly.', ', Trying password123, admin, letmein against accounts , Testing common birthdays like 1990, 1111, 123456 , Using leaked password databases for credential stuffing', 'Try every word in the book as password.', '辞書の単語をパスワードに試す', false),
  (132, 5, 'スパイウェア (Spyware)', '', 'Malware that secretly monitors user activities and sends collected information (browsing habits, keystrokes, data) to a third party.', 'ユーザーの行動を秘密裏に監視し情報を収集するマルウェア (スパイウェア)', 'Used for targeted advertising, identity theft, or corporate espionage.', ', Browser extensions tracking all visited websites , Fake download managers collecting browsing history , Software secretly recording screenshots', 'Software that spies on you.', '秘密に情報を収集するソフト', false),
  (133, 5, 'スパムメール (Spam Mail)', '', 'Unsolicited, bulk emails sent indiscriminately to many recipients, often for advertising or phishing.', '受信者の同意なく大量に送りつけられる迷惑メール (スパムメール)', 'Used by advertisers, scammers, and malware distributors.', ', Nigerian prince inheritance scam emails , Fake lottery winning notifications , Mass emails advertising fake Viagra', 'Junk mail in your inbox.', '大量に送られる迷惑メール', false),
  (134, 5, 'セキュリティホール (Security Hole / Vulnerability)', '', 'A weakness or flaw in system design, implementation, or configuration that can be exploited by attackers.', 'システムの設計や実装上の欠陥で、攻撃に悪用される可能性がある弱点 (セキュリティホール)', 'Existed in all software; needs patching with updates.', ', Heartbleed bug in OpenSSL , Microsoft Windows zero-day vulnerability , Default admin password never changed on router', 'Crack in the digital armor.', 'セキュリティ上の欠陥や弱点', false),
  (135, 5, 'ゼロデイ攻撃 (Zero-day Attack)', '', 'An attack that exploits a previously unknown vulnerability before the software developer has released a patch.', 'セキュリティホールが公開される前にその脆弱性を悪用する攻撃 (ゼロデイこうげき)', 'Used by advanced attackers and nation-states for high-value targets.', ', Attacking Windows before Microsoft knows about bug , Exploiting unknown Chrome vulnerability , Stuxnet using four zero-days against Iran', 'Attack on unknown, unfixed holes.', '修正前に突かれる脆弱性攻撃', false),
  (136, 5, 'ソーシャルエンジニアリング (Social Engineering)', '', 'Psychological manipulation of people into revealing confidential information or performing actions.', '人間の心理的弱点をついて情報を引き出したり行動させる手口 (ソーシャルエンジニアリング)', 'Used to bypass technical security by tricking people.', ', Calling helpdesk pretending to be CEO to reset password , Fake IT person asking for employee login , USB drives lost in parking lot containing malware', 'Hacking humans, not computers.', '人の心理を操作する情報詐取', false),
  (137, 5, 'ドライブバイダウンロード (Drive-by Download)', '', 'An unintentional download of malware that happens when a user visits a compromised or malicious website, without clicking anything.', '悪意のあるWebサイトを閲覧しただけで自動的にマルウェアがダウンロードされる仕組み (ドライブバイダウンロード)', 'Used to infect victims just by visiting a website (no click required).', ', Visiting a hacked news site, malware downloads silently , Malicious ad on legitimate site triggering download , Compromised WordPress plugin infecting visitors', 'Get infected just by visiting a website.', 'サイト閲覧だけで感染する', false),
  (138, 5, 'トロイの木馬 (Trojan Horse)', '', 'Malware disguised as legitimate software, tricking users into installing it, then performing harmful actions.', '正規のソフトウェアを装ってユーザーにインストールさせるマルウェア (トロイのきぼく)', 'Used for backdoor access, data theft, or dropping more malware.', ', Fake Flash Player Update that installs ransomware , Cracked game download containing keylogger , Free PDF converter that steals browser passwords', 'Evil hiding inside something good.', '正規ソフトに偽装した悪意ソフト', false),
  (139, 5, 'パスワードクラック (Password Crack)', '', 'The process of recovering passwords from stored data or by guessing using various attack methods.', 'パスワードを解析・推測して破る行為 (パスワードクラック)', 'Used by attackers or security testers to gain unauthorized access.', ', Cracking hashed passwords from leaked database , Guessing princess123 from common password list , Using rainbow tables to reverse hash', 'Breaking passwords using math and guessing.', 'パスワードを突破する行為', false),
  (140, 5, 'パスワードリスト攻撃 (Password List Attack / Credential Stuffing)', '', 'An attack that uses previously leaked username-password pairs from one site to try to log into other sites.', '他のサービスから漏れたID・パスワードのリストを使って別のサービスにログインを試みる攻撃 (パスワードリストこうげき)', 'Used because people reuse same password on multiple sites.', ', LinkedIn leak used to hack into Gmail accounts , Breached password from old forum used to access bank account , Trying same email/password combo on 10 popular websites', 'Try leaked passwords on other sites.', 'リスト流用のログイン試行攻撃', false),
  (141, 5, 'バックドア (Backdoor)', '', 'A secret method of bypassing normal authentication to gain unauthorized access to a system.', '正規の認証をバイパスしてシステムにアクセスする秘密の入口 (バックドア)', 'Left by developers for maintenance or installed by malware for persistence.', ', Undocumented admin account in router firmware , Malware opening a hidden port for remote control , Developer leaving debug=1 parameter to bypass login', 'Secret entrance to bypass the front door.', '正規ルート外の秘密入口', false),
  (142, 5, 'バッファオーバーフロー攻撃 (Buffer Overflow Attack)', '', 'An attack that writes data beyond a buffer''s allocated memory, corrupting adjacent data and potentially executing malicious code.', 'メモリ領域を超えてデータを書き込み、プログラムを制御する攻撃 (バッファオーバーフローこうげき)', 'Used to crash systems or inject/execute attacker code.', ', Sending more data than expected to crash a server , Overwriting function return address to run malware , Exploiting strcpy() without bounds checking', 'Overflow a cup, spill into dangerous places.', 'メモリ領域からあふれ出る攻撃', false),
  (143, 5, 'フィッシング詐欺 (Phishing Scam)', '', 'A fraud attempt where attackers impersonate legitimate organizations via email, text, or fake websites to trick victims into revealing sensitive info.', '実在の企業を装って個人情報を詐取する手口 (フィッシングさぎ)', 'Used to steal login credentials, credit cards, and personal data.', ', Email pretending to be your bank asking to verify account , Fake login page that looks exactly like Amazon , Text message claiming package delivery needs payment', 'Fake bait to steal your login.', '偽サイトで情報を盗む詐欺', false),
  (144, 5, 'ブルートフォース攻撃 (Brute-force Attack)', '', 'An attack that tries every possible combination of characters (from a to zzzzzz) until the correct password is found.', '考えられる全ての文字列を総当たりで試す攻撃 (ブルートフォースこうげき)', 'Used when dictionary attacks fail, but very time-consuming for strong passwords.', ', Trying aaaaaa, aaaaab, aaaaac... for password cracking , Cracking 4-digit PIN from 0000 to 9999 (10,000 tries) , Server login attempts from a script', 'Try every key until one opens the lock.', '全ての組合せを力ずくで試す', false),
  (145, 5, 'ポートスキャン (Port Scan)', '', 'A technique to probe a server for open ports (communication endpoints) to discover what services are running.', 'サーバのどの通信ポートが開いているかを調べる調査行為 (ポートスキャン)', 'Used by both administrators (to check security) and attackers (to find attack surfaces).', ', Nmap scanning company network for open SSH (port 22) , Checking if web server port 80 and 443 are open , Probing for open database ports (3306 MySQL)', 'Knock on every door to see which open.', '開いている通信口を探す', false),
  (146, 5, 'マルウェア (Malware)', '', 'Malicious software designed to harm, exploit, or otherwise compromise a computer system (includes viruses, worms, trojans, ransomware).', '悪意のあるソフトウェアの総称 (マルウェア)', 'Used for data theft, extortion, espionage, or system destruction.', ', Ransomware encrypting files and demanding Bitcoin , Spyware stealing passwords , Worm spreading across corporate network', 'Bad software = malware.', '悪意あるソフトの総称', false),
  (147, 5, '水飲み場攻撃 (Watering Hole Attack)', '', 'A targeted attack where attackers infect a website that the victim group is known to visit frequently.', '標的グループがよく訪れるWebサイトを経由して感染させる攻撃 (みずのみばこうげき)', 'Used to compromise specific organizations by infecting their trusted external sites.', ', Hacking a financial industry news site to infect bank employees , Compromising a medical journal to attack hospital workers , Poisoning a government contractor''s favorite forum', 'Poison the water hole the target drinks from.', '標的のよく行くサイトを狙う', false),
  (148, 5, 'メール爆弾 (Email Bomb)', '', 'An attack that sends an overwhelming volume of emails to a target address or server to cause disruption.', '大量のメールを送りつけてメールサーバや受信者を機能不全に陥れる攻撃 (メールばくだん)', 'Used for denial of service, harassment, or distraction.', ', Thousands of confirmation emails flooding inbox , Reply-all storm after mass email , Server crashing from 100,000 emails/minute', 'Explode inbox with thousands of emails.', '大量メールで受信者を攻撃', false),
  (149, 5, 'ランサムウェア (Ransomware)', '', 'Malware that encrypts a victim''s files and demands payment (ransom) for the decryption key.', 'ファイルを暗号化し復号と引き換えに身代金を要求するマルウェア (ランサムウェア)', 'Used for extortion, often demanding Bitcoin or other cryptocurrency.', ', WannaCry attack on hospitals (2017) , Colonial Pipeline paying $4.4 million ransom , Police department losing all bodycam footage', 'Your files locked, pay to unlock.', 'データを人質に身代金要求', false),
  (150, 5, 'ワーム (Worm)', '', 'Self-replicating malware that spreads across networks without needing user interaction or attaching to a host file.', 'ネットワークを通じて自己増殖するマルウェア (ワーム)', 'Used to rapidly infect many systems, often for botnets or sabotage.', ', Conficker worm infecting millions of Windows PCs , Morris worm (1988) early internet attack , SQL Slammer crashing servers in 10 minutes', 'Spreads itself like a digital disease.', '自分で増殖して広がるウイルス', false),
  (151, 5, 'セッションハイジャック (Session Hijacking)', '', 'An attack where an attacker steals a user''s session ID (after login) to take over their authenticated session.', 'ログイン後のセッションIDを盗み、ユーザーの認証状態を乗っ取る攻撃 (セッションハイジャック)', 'Used to bypass login and impersonate a user without needing their password.', ', Stealing cookie from public Wi-Fi to access someone''s Facebook , Capturing session token via XSS attack , Man-in-the-middle intercepting session ID', 'Steal your already-open door key.', 'ログイン後の状態を奪う攻撃', false),
  (152, 5, 'DNSキャッシュポイズニング (DNS Cache Poisoning)', '', 'An attack that corrupts a DNS server''s cache to redirect users from legitimate websites to malicious ones.', 'DNSサーバのキャッシュを改ざんし、正規サイトへのアクセスを偽サイトに誘導する攻撃 (DNSキャッシュポイズニング)', 'Used to send victims to fake banking sites or malware downloads without their knowledge.', ', Typing google.com but being sent to fake page , Bank URL resolving to attacker''s phishing server , ISP DNS returning wrong IP for a website', 'Poison the internet''s phone book.', 'DNSの住所録を書き換える', false),
  (153, 5, 'ディレクトリトラバーサル (Directory Traversal / Path Traversal)', '', 'An attack that manipulates file paths to access files and directories stored outside the web root folder.', 'ファイルパスを操作してWebルート外の重要なファイルにアクセスする攻撃 (ディレクトリトラバーサル)', 'Used to read sensitive files like passwords, configs, or source code.', ', ../../../../etc/passwd to read Unix password file , Accessing application configuration file with passwords , Reading Windows boot.ini via URL manipulation', 'Climb out of the web folder to steal files.', 'フォルダ階層をさかのぼる攻撃', false),
  (154, 5, 'クリックジャッキング (Clickjacking)', '', 'A technique where a malicious site hides a transparent button or iframe over a legitimate button to trick users into clicking something they don''t see.', '透明なボタンを装飾し、ユーザーに気付かず別の操作をさせる攻撃 (クリックジャッキング)', 'Used to trick users into enabling camera, liking a page, or transferring money unknowingly.', ', Invisible Enable Camera button disguised as Play Video , Hidden like button stealing social media interactions , Fake Claim Prize that actually transfers Bitcoin', 'You click what you don''t see.', '見えないものをクリックさせる', false),
  (155, 6, 'APOP (Authenticated Post Office Protocol)', '', 'An extension of POP3 that uses MD5 hashing to send passwords encrypted rather than in plain text.', 'POP3に認証機能を追加したプロトコル (エーポップ)', 'Used in legacy email systems to retrieve email from servers with better password security.', ', Old email clients connecting to ISP mail servers , Retrieving email from on-premise legacy mail server , Secure POP email before widespread IMAP use', 'POP3 with password encryption.', '暗号化パスワードのPOP', false),
  (156, 6, 'ARP (Address Resolution Protocol)', '', 'A protocol that maps an IP address to a physical MAC address on a local network.', 'IPアドレスからMACアドレスを調べるプロトコル (エーアールピー)', 'Used by devices to find each other on the same local network (Ethernet/Wi-Fi).', ', Computer asking Who has 192.168.1.1? to find router , Switch learning which port has which MAC , ARP table showing IP-MAC pairs', 'Find hardware address from IP address.', 'IP→MACを変換する仕組み', false),
  (157, 6, 'DHCP (Dynamic Host Configuration Protocol)', '', 'A protocol that automatically assigns IP addresses and network settings to devices on a network.', 'ネットワーク機器に自動でIPアドレスを割り当てるプロトコル (ディーエイチシーピー)', 'Used to avoid manually configuring IP on every device (laptops, phones, printers).', ', Home router giving 192.168.1.x to your phone and laptop , Office network assigning IP to new employee''s computer , Hotel Wi-Fi providing IP upon connection', 'Automatic IP address dispenser.', 'IPアドレス自動割り当て', false),
  (158, 6, 'DNS (Domain Name System)', '', 'The internet''s phone book that translates human-friendly domain names (google.com) into IP addresses (142.250.190.46).', 'ドメイン名とIPアドレスを変換する仕組み (ディーエヌエス)', 'Used every time you type a website name into a browser.', ', google.com → 142.250.190.46 , Typing amazon.com without remembering IP numbers , Email routing via MX records', 'Translates names to numbers on internet.', '名前→数字を変換する仕組み', false),
  (159, 6, 'ESSID (Extended Service Set Identifier)', '', 'The name of a Wi-Fi network that users see and select when connecting.', '無線LANのネットワーク名 (ESSID / エッシド)', 'Used to identify and connect to a specific wireless network among many.', ', Selecting Starbucks Wi-Fi from your phone , Home network named MyHome2.4G , Office network Corp_WiFi visible to employees', 'Your Wi-Fi network''s name.', 'Wi-Fiネットワークの名前', false),
  (160, 6, 'FTP (File Transfer Protocol)', '', 'A standard network protocol for transferring files between a client and server on a computer network.', 'ファイル転送のための標準プロトコル (エフティーピー)', 'Used to upload website files to a hosting server or download large files.', ', Uploading HTML files to web hosting server , Downloading Linux ISO images from mirrors , WordPress plugin installation via FTP', 'Move files between computers.', 'ファイル転送の標準手順', false),
  (161, 6, 'HTTP (HyperText Transfer Protocol)', '', 'The foundation protocol for data communication on the World Wide Web, used for loading web pages.', 'Webページを表示するための通信プロトコル (エイチティーティーピー)', 'Used by browsers to request and receive web pages, images, and videos.', ', Typing http://example.com in browser (unsecured) , Browser sending GET request for index.html , Communication between frontend and backend', 'Web page delivery protocol (not secure).', 'Webの基本通信ルール', false),
  (162, 6, 'HTTPS (HyperText Transfer Protocol Secure)', '', 'The secure version of HTTP using SSL/TLS encryption to protect data between browser and website.', 'HTTPに暗号化機能を追加した安全なプロトコル (エイチティーティーピーエス)', 'Used for banking, shopping, login pages, and any site handling sensitive data.', ', Banking website with padlock icon in address bar , Gmail login over HTTPS , Amazon checkout page', 'Secure web communication with lock.', '暗号化されたWeb通信', false),
  (163, 6, 'ICMP (Internet Control Message Protocol)', '', 'A protocol used for error reporting and diagnostic functions like ping and traceroute.', 'ネットワークの診断やエラー通知に使うプロトコル (アイシーエムピー)', 'Used by network administrators to test connectivity and troubleshoot.', ', ping google.com to check if internet works , traceroute to see path packets take , Destination Unreachable error messages', 'Internet''s diagnostic and error reporting tool.', '通信状態確認の仕組み', false),
  (164, 6, 'IMAP (Internet Message Access Protocol)', '', 'An email protocol that stores messages on the server and synchronizes across multiple devices.', 'メールをサーバ上で管理し複数端末で同期するプロトコル (アイマップ)', 'Used by email clients (Outlook, Gmail app, Thunderbird) to access mail.', ', Reading same email on phone, laptop, tablet with all showing read , Folder structure (Inbox, Sent) synced across devices , Gmail using IMAP for third-party clients', 'Email stays on server, syncs everywhere.', 'サーバでメールを同期する', false),
  (165, 6, 'IP (Internet Protocol)', '', 'The principal protocol for addressing and routing packets of data across networks to their destination.', 'データを宛先まで届けるためのインターネットの基幹プロトコル (アイピー)', 'Used in every internet communication to provide addressing and packet forwarding.', ', Sending data from Tokyo to New York server , IP header containing source and destination addresses , Routing packet through multiple routers', 'Internet''s postal service for data.', 'データを届ける基本ルール', false),
  (166, 6, 'MIME (Multipurpose Internet Mail Extensions)', '', 'An extension to email that allows sending non-text attachments like images, audio, and video.', 'メールでテキスト以外の添付ファイルを送るための拡張仕様 (マイム)', 'Used by email systems to handle file attachments and rich content.', ', Sending a photo.jpg via email , Receiving PDF attachment in Outlook , Embedding images directly in email body', 'Email attachments and rich content support.', 'メール添付ファイルの仕様', false),
  (167, 6, 'NNTP (Network News Transfer Protocol)', '', 'A protocol used for reading and posting articles to Usenet newsgroups (early internet forums).', 'ネットニュース(Usenet)の記事を配信するプロトコル (エヌエヌティーピー)', 'Used by Usenet servers and newsreader clients (now largely obsolete).', ', Reading alt.comp.freeware discussions , Downloading binaries from Usenet groups , News server syncing between providers', 'Old internet forum protocol.', '昔のネット議論掲示板の仕組み', false),
  (168, 6, 'NTP (Network Time Protocol)', '', 'A protocol for synchronizing computer clocks over a network to a reference time source (e.g., atomic clocks).', 'ネットワーク上の機器の時刻を正確に同期するプロトコル (エヌティーピー)', 'Used to ensure logs, transactions, and authentication have accurate timestamps.', ', Windows syncing time with time.windows.com , Bank server matching timestamp to millisecond , Authentication failing if client/server clocks mismatch', 'Keeps all devices on same clock.', 'ネットワーク時刻同期の仕組み', false),
  (169, 6, 'POP (Post Office Protocol)', '', 'A protocol for retrieving emails from a server, typically downloading and deleting them from the server.', 'サーバからメールをダウンロードして受信するプロトコル (ポップ)', 'Used by email clients where users want to store mail locally and free server space.', ', Downloading all emails to Outlook then deleting from server , Reading mail offline after download , Simple email setup on older systems', 'Download email, often delete from server.', 'メールをダウンロードする方法', false),
  (170, 6, 'PPP (Point-to-Point Protocol)', '', 'A data link protocol used to establish direct network connections between two nodes (e.g., computer to ISP via modem).', '2点間を直接接続するための通信プロトコル (ピーピーピー)', 'Used historically for dial-up internet connections, VPNs, and DSL.', ', 56k modem dial-up connecting to AOL , PPPoE for fiber internet authentication , VPN tunnel establishment', 'Direct connection between two points.', '1対1の接続を確立する', false),
  (171, 6, 'S/MIME (Secure/Multipurpose Internet Mail Extensions)', '', 'A standard for public key encryption and digital signing of email messages, adding security to MIME.', 'MIMEに暗号化と電子署名を追加した安全なメール仕様 (エス/マイム)', 'Used by corporate and government email for end-to-end encryption and authentication.', ', Sending encrypted email only recipient can read , Digitally signing email to prove it''s from you and not altered , Government inter-office secure communication', 'Secure version of email attachments and content.', '暗号化と署名のメール拡張', false),
  (172, 6, 'SMTP (Simple Mail Transfer Protocol)', '', 'The standard protocol for sending emails from a client to a server or between mail servers.', 'メールを送信するための標準プロトコル (エスエムティーピー)', 'Used whenever you send an email (not receiving).', ', Gmail sending your message to recipient''s server , Mail server to mail server delivery , WordPress contact form emailing you', 'Email sending and relaying protocol.', 'メール送信の標準手順', false),
  (173, 6, 'SNMP (Simple Network Management Protocol)', '', 'A protocol for monitoring and managing network devices like routers, switches, servers, and printers.', 'ネットワーク機器を監視・管理するためのプロトコル (スニンプ)', 'Used by network administrators to check device health, bandwidth, and errors.', ', Monitoring router CPU usage and temperature , Printer alerting when toner is low , SolarWinds tracking network performance', 'Remote health check for network devices.', 'ネットワーク監視の仕組み', false),
  (174, 6, 'SSH (Secure Shell)', '', 'A cryptographic network protocol for secure remote login and command execution over unsecured networks.', '暗号化を使って安全にリモート接続するプロトコル (エスエスエイチ)', 'Used by system administrators to manage servers securely (replaces Telnet).', ', ssh user@server.com to access cloud server , SCP for secure file copy , Port forwarding for encrypted tunnel', 'Secure remote terminal access with encryption.', '安全なリモート接続方法', false),
  (175, 6, 'SSL (Secure Sockets Layer)', '', 'An older cryptographic protocol for encrypting internet connections (superseded by TLS but still commonly used in naming).', 'Web通信を暗号化するプロトコル (エスエスエル / TLSに進化)', 'Used to secure HTTPS websites, though modern systems use TLS. Still called SSL certificate commonly.', ', Padlock icon in browser address bar , E-commerce checkout page encryption , SSL Certificate purchased for websites', 'Old name for web encryption (now TLS).', '暗号化通信の旧名(現TLS)', false),
  (176, 6, 'TCP (Transmission Control Protocol)', '', 'A reliable, connection-oriented protocol that ensures data packets are delivered in order and without errors.', '確実に順番通り届ける信頼性重視のプロトコル (ティーシーピー)', 'Used for applications where data integrity matters: web, email, file transfer.', ', Loading a complete webpage without missing parts , Downloading a file with automatic retransmission of lost packets , Email delivery guaranteeing all text arrives', 'Reliable, in-order delivery with error check.', '確実にデータを届ける方式', false),
  (177, 6, 'TELNET (Teletype Network)', '', 'An older protocol for remote terminal access over a network, now largely replaced by SSH due to lack of encryption.', 'リモートでコンピュータを操作する旧式プロトコル (テルネット)', 'Used rarely today, mostly for legacy systems or local debugging (unencrypted, so insecure).', ', Connecting to old mainframe at a university , Troubleshooting router on local network without encryption , Testing manual HTTP requests to a server', 'Old unencrypted remote terminal access.', '暗号化なしのリモート接続(旧式)', false),
  (178, 6, 'UDP (User Datagram Protocol)', '', 'A fast, connectionless protocol that sends packets without guaranteeing delivery or order (no retransmission).', '速さ重視で届かない可能性もあるプロトコル (ユーザーデータグラムプロトコル / ユーディーピー)', 'Used for real-time applications where speed beats perfection: streaming, gaming, VoIP.', ', Zoom video call: missing few pixels better than delay , Online game: player positions update fast even if one packet lost , DNS lookup query (fast, short message)', 'Fast, fire-and-forget data delivery.', '速いが届かないこともある通信', false),
  (179, 6, 'WPA2 (Wi-Fi Protected Access 2)', '', 'A security protocol for Wi-Fi networks that uses AES encryption for strong protection (replaced WEP and WPA).', 'Wi-Fiネットワークを守る暗号化規格 (ダブリュピーエーツー)', 'Used on most home and office Wi-Fi routers to prevent unauthorized access and eavesdropping.', ', Entering password for HomeWiFi on phone (WPA2) , Office Wi-Fi requiring WPA2 enterprise with username , Router configuration showing WPA2-PSK option', 'Standard Wi-Fi password security today.', '現在のWi-Fi暗号化標準', false);